mapper.select:
SELECT COUNT(*)
FROM FWK_BIZ_APP
WHERE BIZ_APP_ID = #{bizAppId}

SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT , c.CODE_NAME AS QUE_NAME_DISPLAY FROM FWK_BIZ_APP b LEFT JOIN FWK_CODE c ON c.CODE_GROUP_ID = 'FR20003' AND c.CODE = b.QUE_NAME
ORDER BY
b.BIZ_APP_NAME b.DUP_CHECK_YN c.CODE_NAME b.LOG_YN b.BIZ_APP_ID
DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
